T101_200 = {
101: {"nativeDefinition": "The situation cannot be changed; accept it.", "japaneseMeaning": "仕方ない、それが現実", "etymology": "it is what it is（それがそれだ）で、変えられない現実を受け入れる表現。", "examples": {"B": "運転免許の試験落ちた。バカみたいだけど、仕方ない。", "C": "スーパーで一つだけ買いに行って、その一つを買い忘れた。まあ、仕方ない。", "D": "状況は変えられない。"}},
102: {"nativeDefinition": "Something that reminds one of the past.", "japaneseMeaning": "懐かしの、ノスタルジーを呼ぶ", "etymology": "throw back（過去に投げ返す）で、昔を思い出させるものを表す。", "examples": {"B": "この写真、若かった頃を思い出す。", "C": "この曲、90年代を思い出す名曲だね。", "D": "過去の何かの思い出。"}},
103: {"nativeDefinition": "To stay until the end of something boring or unpleasant.", "japaneseMeaning": "（退屈なものを）最後まで耐えて見る・聞く", "etymology": "sit through（座り続ける）で、退屈なものを最後まで我慢することを表す。", "examples": {"B": "あのドラマ、頭が麻痺するほど退屈だったけど、彼女が一緒に見たいから最後まで耐えた。", "C": "結婚式で一番つらいのは、スピーチを全部最後まで聞かなきゃいけないことじゃない？", "D": "何かの終わりまで留まる。"}},
104: {"nativeDefinition": "Ready and eager to listen.", "japaneseMeaning": "熱心に聞くよ、耳を傾ける", "etymology": "all ears（すべて耳）で、全身で聞く姿勢を表す。", "examples": {"B": "プログラミングを教えてくれる人がいたら、ぜひ聞きたい。", "C": "他業界に進出するのは理にかなってると思うけど、もっといいアイデアがあれば聞きたい。", "D": "聞く準備ができている。"}},
105: {"nativeDefinition": "To make a special effort to do something.", "japaneseMeaning": "わざわざ〜する、特別に努力して〜する", "etymology": "go out of one's way（道を外れる）で、わざわざ遠回りして努力することを表す。", "examples": {"B": "わざわざヴィンスのボクシングを手伝ったのに裏目に出た。今はいつも俺をボコボコにする。", "C": "カンガルー肉は初めて食べた。まあまあだけど、わざわざ食べに行くほどじゃない。", "D": "特別な努力をしてやる。"}},
106: {"nativeDefinition": "Vague, indecisive, or lacking conviction.", "japaneseMeaning": "曖昧な、優柔不断な", "etymology": "wishy-washy（ふわふわした）の擬態語的表現。", "examples": {"B": "彼の指示がちょっと曖昧だから、意味をはっきりさせるために質問するつもり。", "C": "優柔不断な人は本当に耐えられない。", "D": "曖昧な、優柔不断な。"}},
107: {"nativeDefinition": "A person who spoils others' fun.", "japaneseMeaning": "興ざめさせる人、空気読めない人", "etymology": "kill（殺す）＋ joy（喜び）で、楽しみを台無しにする人を表す。", "examples": {"B": "今回はジョニーをランチに連れてこないで。あいつほんと興ざめするから。", "C": "YouTubeで好きな曲を再生する前に悲しい広告が流れるの、ほんと興ざめ。", "D": "楽しい雰囲気を台無しにする人や物。"}},
108: {"nativeDefinition": "Slightly ahead in skill, knowledge, or preparation.", "japaneseMeaning": "一歩先を行く、一歩リードしている", "etymology": "one step ahead（一歩先）で、相手より優位に立つことを表す。", "examples": {"B": "時事のポッドキャストをたくさん聞いて、他人より一歩先にいるようにしてる。", "C": "友達は一歩先である必要はないって言うけど、成功してるからそう言えるんだと思う。", "D": "何かや誰かより少し上手または準備ができている。"}},
109: {"nativeDefinition": "Worth spending one's time on.", "japaneseMeaning": "（時間をかける）価値がある", "etymology": "worth one's while（自分の時間の価値がある）で、時間を使う価値があることを表す。", "examples": {"B": "この映画、時間をかける価値ある？それとも他のを見た方がいい？", "C": "ワークショップはあまり時間をかける価値がなかったから、こっそり抜け出した。", "D": "（人の）時間を費やす価値がある。"}},
110: {"nativeDefinition": "To be selected or succeed in passing a standard.", "japaneseMeaning": "基準をクリアする、合格する", "etymology": "make the cut（カットラインを超える）がゴルフ用語から転じ、選考を通過することを表す。", "examples": {"B": "どんなに頭が良くても、努力しなければ基準をクリアできない。", "C": "この点数で基準をクリアできると思う？", "D": "基準に達する。"}},
111: {"nativeDefinition": "Being cared for by capable and trustworthy people.", "japaneseMeaning": "安心して任せられる、良い人に預けられている", "etymology": "in good hands（良い手の中）で、信頼できる人に任されていることを表す。", "examples": {"B": "クラウドは便利な保険だけど、普段は信用しない。でもGoogleならデータは安心して任せられる。", "C": "先生がアルバートなら安心だよ。良い人に預けられてる。", "D": "安全な。"}},
112: {"nativeDefinition": "A beginning that suggests future success.", "japaneseMeaning": "有望なスタート、良い出だし", "etymology": "promising（有望な）＋ start（始まり）で、良い兆しのある開始を表す。", "examples": {"B": "F1で速い初回ラップは有望なスタートだけど、それがすべてじゃない。", "C": "今週初めて電車が定刻通りだった。滅多にないことだから、良い一日の出だしだと思う。", "D": "とても良い始まり。"}},
113: {"nativeDefinition": "Designed or intended for a particular group or purpose.", "japaneseMeaning": "（〜向けに）作られている、〜を対象とした", "etymology": "geared toward（〜に向けて調整された）で、特定の対象に合わせたことを表す。", "examples": {"B": "このチャンネルで子供向けの動画を作るのもアリだよ。きっと楽しい。", "C": "このプログラムは犯罪者を正しい道に戻すことを目的にしている。", "D": "何かや誰かに適するよう設計された。"}},
114: {"nativeDefinition": "One's most trusted assistant or right-hand person.", "japaneseMeaning": "右腕、最も信頼できる部下", "etymology": "right-hand man（右手の男）で、最も頼れる補佐役を表す。", "examples": {"B": "チャールズは俺の右腕だ。忙しいときに社員をまとめてくれる。", "C": "ジムは彼女の右腕みたい。いつも波長が合ってる。", "D": "最も信頼できる補佐。"}},
115: {"nativeDefinition": "Regularly and predictably, without fail.", "japaneseMeaning": "きっちり、規則正しく", "etymology": "clockwork（時計の仕組み）のように正確に動くという比喩。", "examples": {"B": "ベンはきっちり毎日6時ピッタリにバスケの練習に来る。", "C": "きっちり毎日10時に朝食を食べてる。なんとなく。", "D": "定期的に。"}},
116: {"nativeDefinition": "A person or situation with no hope of success.", "japaneseMeaning": "手に負えない、どうしようもない", "etymology": "lost cause（失われた大義）で、成功の見込みがないことを表す。", "examples": {"B": "ダンスを教えてくれる人はたくさんいたけど、俺はどうしようもないと思う。", "C": "親が俺を問題児だと思ってるのはむしろ嬉しい。勉強しろって言われたことがない。どうしようもないってわかってるから。", "D": "成功の見込みがない人や物。"}},
117: {"nativeDefinition": "Not typical of someone's usual behavior.", "japaneseMeaning": "いつもと違う、らしくない", "etymology": "out of character（役柄から外れている）で、普段と違う行動を表す。", "examples": {"B": "ティムがネクタイしてたの？いつもと違うね。", "C": "ジョージアが仕事で半袖ハードなんて、いつもと違う。何かあったに違いない。", "D": "その人らしくない。"}},
118: {"nativeDefinition": "To contact someone, usually briefly.", "japaneseMeaning": "（人に）連絡する、声をかける", "etymology": "give a shout（叫びをかける）で、気軽に連絡することを表す。", "examples": {"B": "買い物に行くとき連絡して。一緒に行くから。", "C": "明日休みだけど、何か困ったら連絡して。", "D": "（人に）知らせる。"}},
119: {"nativeDefinition": "Used to introduce an important point.", "japaneseMeaning": "実は、ここがポイントなんだけど", "etymology": "here's the thing（問題はここだ）で、本題を切り出す表現。", "examples": {"B": "実はね、一つのカゴに全部の卵を入れるのはバカげてると思う。株式以外にも投資すべきだ。", "C": "実は、意見が合わなくても人を嫌うべきじゃないと思う。", "D": "言いたいことがある。"}},
120: {"nativeDefinition": "Someone who talks about doing things but never actually does them.", "japaneseMeaning": "口だけの人、言うだけで行動しない", "etymology": "all talk（すべて話）で、行動が伴わないことを表す。", "examples": {"B": "あいつ口だけだよ。本当に天変地異でも起こして昇進を手伝うような人じゃない。", "C": "口だけじゃん。いつも言うだけで実行しない。", "D": "何かをすると言うが決してしない人。"}},
121: {"nativeDefinition": "What people do is more important than what they say.", "japaneseMeaning": "行動は言葉より雄弁だ", "etymology": "actions（行動）がwords（言葉）よりlouder（大きい声）という直喩的なことわざ。", "examples": {"B": "行動は言葉より雄弁だよね。口先だけ安いでしょ。実際に何かしたの？", "C": "直すって言ったのに、何もしてないじゃん。行動は言葉より雄弁だよ。", "D": "人がすることは言うことより重要だ。"}},
122: {"nativeDefinition": "To progress without clear direction or purpose.", "japaneseMeaning": "（特に目的なく）流れに任せて進む", "etymology": "drift（漂う）＋ along（一緒に）で、方向性なく進むことを表す。", "examples": {"B": "兄が人生で何してるのかわからない。ただ流れに任せてて、何にも本気で取り組んでない。", "C": "仕事はここ数日流れに任せてたから、そろそろペース上げないと。締め切りが近い。", "D": "方向性なく進む。"}},
123: {"nativeDefinition": "At risk; in a vulnerable position.", "japaneseMeaning": "（〜が）危険にさらされている、賭けられている", "etymology": "on the line（線の上）で、危険に晒されていることを表す。", "examples": {"B": "有名人は怪しいことをして評判を危険にさらすべきじゃない。", "C": "崖の縁で自撮りする人が理解できない。バカな写真のために命を賭けたくない。", "D": "危険とリスク。"}},
124: {"nativeDefinition": "A narrow escape from danger or disaster.", "japaneseMeaning": "危ないところだった、九死に一生", "etymology": "close shave（ギリギリの剃り）で、かろうじて逃れたことを表す。", "examples": {"B": "昨日道を渡ってたら、突然車が現れて後ろからほとんど当たるところだった。", "C": "最近何度か危ないところだったから、明日お寺に行って浄化しようと思う。", "D": "危険からかろうじて逃れること。"}},
125: {"nativeDefinition": "To persuade or pressure someone into doing something.", "japaneseMeaning": "（人を）無理やり巻き込む、引きずり込む", "etymology": "rope into（ロープで引き込む）で、強引に参加させることを表す。", "examples": {"B": "今夜遅くまで残らなきゃ。明日朝までに終わらせなきゃいけないクレイジーなプロジェクトに巻き込まれた。", "C": "ユウをバスケ部に巻き込めたんだって？いいね！", "D": "（人の）意志に反して何かに関与させる。"}},
126: {"nativeDefinition": "Quite difficult or harsh.", "japaneseMeaning": "かなり厳しい、大変", "etymology": "pretty（かなり）＋ tough（厳しい）の強調表現。", "examples": {"B": "昨日電車でビルが時計をなくしたのを聞いた。かなり大変だね。", "C": "アダムがソフィアの二番手を務めるのはかなり厳しい状況だ。彼女は権力者へのゴマすりがうまいだけ。", "D": "かなり不幸または厳しい。"}},
127: {"nativeDefinition": "To carefully find out how someone feels or how something is.", "japaneseMeaning": "（様子を）探る、感触を確かめる", "etymology": "feel out（感触を確かめる）で、慎重に状況を探ることを表す。", "examples": {"B": "噂でジョーとカイリーが赤ちゃんを授かるって聞いたけど、本人たちに探って確認する。", "C": "スーツは法律を面白く簡単に見せてくれるけど、まだ感触を確かめてるところ。", "D": "慎重に何かや誰かについて知識を得る。"}},
128: {"nativeDefinition": "Playful, teasing conversation.", "japaneseMeaning": "軽口、からかい合い", "etymology": "banter（軽口）の名詞用法。", "examples": {"B": "このコメントはただの軽口だと思うけど、時々本気で受け取っちゃう。", "C": "マイクは本当に無難な人だと思ってたけど、軽口を言うのが好きなんだね。", "D": "ユーモアのある、からかいの会話。"}},
129: {"nativeDefinition": "Be careful what you ask for; you may regret getting it.", "japaneseMeaning": "願いが叶うと災いが転じる、望む前によく考えろ", "etymology": "wish（願い）に careful（注意深い）を重ねたことわざ。", "examples": {"B": "もっと上司に気づいてほしい？願いが叶うと災いが転じるよ。しばらく目立たない方が悪いことじゃないかも。", "C": "彼氏のすべてを知りたいの？願いが叶うと災いが転じるよ。知らない方が幸せなこともある。", "D": "願っていることをよく考えて結果を検討しろ。"}},
130: {"nativeDefinition": "Through both good times and bad times.", "japaneseMeaning": "良い時も悪い時も、どんな時も", "etymology": "thick（厚い＝困難）とthin（薄い＝順調）で、あらゆる状況を表す。", "examples": {"B": "彼女とは良い時も悪い時も一緒にいたから、振られたときは本当に不意打ちだった。", "C": "夫婦は良い時も悪い時もお互いのそばにいなきゃいけない。それだけのこと。", "D": "困難な時期でさえも。"}},
131: {"nativeDefinition": "To pretend to agree or cooperate.", "japaneseMeaning": "（とりあえず）合わせる、付き合う", "etymology": "play along（一緒に演じる）で、表面上協力することを表す。", "examples": {"B": "正しい方向に進んでるかわからないけど、とりあえず順調だって言って。上司がパニックになるのは避けたい。", "C": "両親に彼女のことを好意的に思わせたいから、ランチの終わりまで付き合ってくれる？後で理由を説明する。", "D": "協力する。"}},
132: {"nativeDefinition": "To learn skills while working rather than through formal study.", "japaneseMeaning": "実務で学ぶ、働きながら覚える", "etymology": "on the job（仕事中に）で、実践を通じて学ぶことを表す。", "examples": {"B": "教科書を読むより実務で学ぶ方が好き。", "C": "エイミーから短期集中で教わるのもいいと思ったけど、実務で学ぶ方がずっと楽だった。", "D": "働きながら学ぶ。"}},
133: {"nativeDefinition": "Confined indoors; unable to go outside.", "japaneseMeaning": "（家に）閉じ込められた、外出できない", "etymology": "coop（鶏小屋）＋ up（閉じ込める）で、狭い空間に閉じ込められることを表す。", "examples": {"B": "雨がやまないかな。一人で家に閉じ込められてうんざり。", "C": "おばあちゃんは大好きだけど、一日中一緒に閉じ込められたら気が狂いそう。同じ話の繰り返しだし。", "D": "閉じ込められた。"}},
134: {"nativeDefinition": "An indication that something may be wrong or dangerous.", "japaneseMeaning": "警告サイン、危険信号", "etymology": "warning（警告）＋ sign（兆候）の複合語。", "examples": {"B": "金曜の夜にレストランが空いてたら、だいたい大きな警告サインだ。", "C": "このドットコムバブルの崩壊は不況の警告サイン？嵐の前の静けさに過ぎないといいけど。", "D": "警告。"}},
135: {"nativeDefinition": "To relax and rest, especially by putting one's feet up.", "japaneseMeaning": "くつろぐ、足を投げ出して休む", "etymology": "put one's feet up（足を上げる）で、くつろいで休むことを表す。", "examples": {"B": "クリスマスに足を投げ出して休むのが本当に楽しみ。ここ数週間大変だったから。", "C": "たまには足を投げ出して休んでもいいんじゃない。すごく疲れてるみたいだし。", "D": "リラックスする。"}},
136: {"nativeDefinition": "Support and encouragement rather than practical help.", "japaneseMeaning": "精神的な支え、応援", "etymology": "moral（精神的な）＋ support（支援）で、実利的でない支えを表す。", "examples": {"B": "次の試合に精神的な支えに行くよ。力になると思うなら。", "C": "姉はいつも手伝ってくれるし、精神的な支えもしてくれる。", "D": "心理的支援。"}},
137: {"nativeDefinition": "To give approval or permission.", "japaneseMeaning": "（人に）OKを出す、許可する", "etymology": "give the OK（オーケーを与える）で、承認することを表す。", "examples": {"B": "伝統的だから、プロポーズする前に彼女の両親からOKをもらう必要がある。", "C": "やっと母が新しいゲームを買っていいってOK出してくれた。嬉しい。", "D": "（人に）承認を与える。"}},
138: {"nativeDefinition": "An initial version or draft of something.", "japaneseMeaning": "初稿、最初の版", "etymology": "first（最初の）＋ cut（版）で、最初の仕上がりを表す。", "examples": {"B": "月曜までに初稿を渡すよ。モックアップするのそんなに時間かからないはず。", "C": "数ヶ月前に渡した初稿以来、動画編集のスキルはだいぶ上達した。", "D": "初期の草案。"}},
139: {"nativeDefinition": "To bring someone somewhere reluctantly or against their will.", "japaneseMeaning": "（人を）無理やり連れて行く", "etymology": "drag along（引きずって連れて行く）で、嫌がる人を連れていくことを表す。", "examples": {"B": "オペラには興味ないけど、彼女に無理やり連れて行かれた。", "C": "この会議に無理やり連れてこられたけど、たくさん学べそう。", "D": "（人の）意志に反して連れて行く。"}},
140: {"nativeDefinition": "To progress with minimal effort.", "japaneseMeaning": "（楽をして）なんとか進む、波に乗る", "etymology": "coast（慣性で進む）＋ along（一緒に）で、努力せず進むことを表す。", "examples": {"B": "仕事で楽をしてなんとか進んで毎年昇進できるといいんだけど、無理だよね。", "C": "人生を楽して進めることもできるけど、あまり期待しない方がいい。", "D": "最小限の努力で進む。"}},
141: {"nativeDefinition": "A person who is cheerful and good-humored about setbacks.", "japaneseMeaning": "スポーツマンシップのある人、いい性格の人", "etymology": "good sport（良いスポーツマン）で、負けても潔い人を表す。", "examples": {"B": "ジャックが大統領の顔に巨大なパイを投げたのに、大統領は大笑いした。いい性格だね。", "C": "ナンシーは本当にいい人。歌が嫌いなのにカラオケパーティーに来て一緒に歌ってくれた。", "D": "寛大な人。"}},
142: {"nativeDefinition": "Articulate and eloquent in speech.", "japaneseMeaning": "話し方がうまい、雄弁な", "etymology": "well（上手に）＋ spoken（話された）で、言葉遣いが巧みなことを表す。", "examples": {"B": "ケビンはいつも話し方がうまい。ためらいなく、無駄なことを言わない。", "C": "話し方がうまいからって、この人の言うことを全部鵜呑みにしちゃダメだよ。", "D": "雄弁な。"}},
143: {"nativeDefinition": "To watch someone too closely; to pressure them.", "japaneseMeaning": "（人の）後ろに張り付く、監視する", "etymology": "breathe down one's neck（首の後ろで息をする）で、過度に監視することを表す。", "examples": {"B": "お母さん、後ろに張り付かないで。自分のペースで勉強したいの。", "C": "彼女と話すとき気をつけて。嫉妬深い彼氏がいつも後ろに張り付いてる。", "D": "（人を）過度に監視する。"}},
144: {"nativeDefinition": "Nervous and easily startled.", "japaneseMeaning": "ビクビクする、神経質な", "etymology": "jumpy（飛び跳ねる）で、すぐ驚く状態を表す。", "examples": {"B": "うちの犬、今すごくビクビクしてるから、大きな音を出さないで。", "C": "今日なんでそんなにビクビクしてるの？コーヒー飲みすぎ？", "D": "不安で落ち着かない。"}},
145: {"nativeDefinition": "To gain experience or achieve something.", "japaneseMeaning": "（経験などを）積む、身につける", "etymology": "under one's belt（ベルトの下）で、達成・習得したことを表す。", "examples": {"B": "バリスタとして5年の経験を積んだから、ついに自分のカフェを開ける。", "C": "このゲーム最高。もう2勝積んでる。やり方教えてあげるよ。", "D": "何かを得る、蓄積する。"}},
146: {"nativeDefinition": "To contribute to or influence something.", "japaneseMeaning": "（〜に）寄与する、影響を与える", "etymology": "feed into（〜に供給する）で、次の段階に活かされることを表す。", "examples": {"B": "フィードバックありがとう。次の改訂に活かすよ。", "C": "今日話し合ったことは、今後の計画に必ず活かされる。", "D": "何かに貢献する。"}},
147: {"nativeDefinition": "Someone or something that spoils the mood.", "japaneseMeaning": "興ざめ、雰囲気を壊す人", "etymology": "buzz（盛り上がり）＋ kill（殺す）で、盛り上がりを台無しにするものを表す。", "examples": {"B": "DJが昨夜のリミックス流したの、ほんと興ざめ。クラブでアンガムソングなんて。", "C": "サムをディナーに誘うのやめた。いつも興ざめするから。", "D": "楽しい雰囲気を台無しにする人や物。"}},
148: {"nativeDefinition": "To concentrate one's effort on achieving something.", "japaneseMeaning": "（〜に）本気で取り組む、集中する", "etymology": "put one's mind to（心を向ける）で、真剣に努力することを表す。", "examples": {"B": "本気で取り組めば、ASMRとして成功できるよ。", "C": "自分を信じて本気で取り組めば、何でも達成できる。意志あるところに道は開ける。", "D": "何かに多大な努力を向ける。"}},
149: {"nativeDefinition": "To meet the requirements or be suitable.", "japaneseMeaning": "（条件に）合う、ぴったりだ", "etymology": "fit the bill（請求書に合う）で、要件を満たすことを表す。", "examples": {"B": "小売の経験があるから、この役にぴったりだと思う。", "C": "情熱的なボランティアを探してる。条件に合う人知らない？", "D": "要件に合う。"}},
150: {"nativeDefinition": "So good that it is hard to believe.", "japaneseMeaning": "良すぎて信じられない", "etymology": "too good to be true（本当には良すぎる）で、裏があるのではと疑われるほど良いことを表す。", "examples": {"B": "なんか怪しい。覚えてない宝くじでハワイ旅行当たった。良すぎて信じられない。", "C": "良すぎて信じられないってわかってるけど、俺の指示に従えば数日で大金を稼げる。", "D": "信じがたいほど素晴らしい。"}},
151: {"nativeDefinition": "A trivial problem affecting privileged people.", "japaneseMeaning": "先進国の悩み、贅沢な悩み", "etymology": "first world（先進国）＋ problem（問題）で、裕福な国の些細な悩みを表す。", "examples": {"B": "贅沢な悩みだけど、財布に現金が多すぎるとすごくイライラする。", "C": "全部の通知オフにしたらFOMOになった。完全に先進国の悩み。", "D": "些細な問題。"}},
152: {"nativeDefinition": "To obtain benefit or enjoyment from something.", "japaneseMeaning": "（〜から）最大限を引き出す、得る", "etymology": "get out of（〜から取り出す）で、何かから利益を得ることを表す。", "examples": {"B": "大学生活を最大限楽しみたいから、キャンパス活動にできるだけ参加する。", "C": "このゲームから何かを得るには、全力でやらなきゃ。", "D": "何かから何かを得る。"}},
153: {"nativeDefinition": "To ignore or dismiss someone or something.", "japaneseMeaning": "（〜を）無視する、軽く扱う", "etymology": "blow off（吹き飛ばす）で、無視することを表す。", "examples": {"B": "今日は気分じゃなくて医者の予約を無視した。後ですごく罪悪感があった。もう二度としない。", "C": "オフィスの近くにいたから連絡したのに無視された。忙しいのはわかるから気にしてない。", "D": "何かや誰かを無視する。"}},
154: {"nativeDefinition": "Warning that a plot reveal is coming.", "japaneseMeaning": "ネタバレ注意", "etymology": "spoiler（ネタバレ）＋ alert（警告）の造語。", "examples": {"B": "ネタバレ注意、このシーンの後にこのキャラが死ぬ。", "C": "ネタバレ注意、ルーク・スカイウォーカーとレイア姫は兄妹。", "D": "知りたくない情報が明かされようとしているという警告。"}},
155: {"nativeDefinition": "To read someone's message without replying.", "japaneseMeaning": "（メッセージを）既読スルーする", "etymology": "leave on read（既読のままにする）で、返信しないことを表す。", "examples": {"B": "今日既読スルーしたのは、スマホがバグってたから。勘違いしないで。", "C": "彼女は好意がないから既読スルーしたって言ってた。本当にストレートだよね。", "D": "メッセージを読んで返信しない。"}},
156: {"nativeDefinition": "Excessively anxious or fearful about something.", "japaneseMeaning": "（〜について）被害妄想がちな、不安になりすぎる", "etymology": "paranoid（偏執的な）で、過度に不安になることを表す。", "examples": {"B": "ミュートになってるって表示されてるけど、まだ聞こえてないか少し不安。", "C": "タクシー運転手にぼったくられるのがいつも心配だから、Uberにしてる。", "D": "何かについて極度に心配または怖がる。"}},
157: {"nativeDefinition": "To get along well with someone immediately.", "japaneseMeaning": "（人と）すぐに意気投合する、波長が合う", "etymology": "click（カチッと音がする）で、すぐに噛み合うことを表す。", "examples": {"B": "ルームメイトとすぐに意気投合できて、すごく嬉しい。", "C": "頭がいいだけの人とは波長が合わない。実用的じゃない。", "D": "（人と）すぐに仲良くなる。"}},
158: {"nativeDefinition": "To happen or unfold in a particular way.", "japaneseMeaning": "（物事が）展開する、進む", "etymology": "play out（演じられる）で、状況が展開することを表す。", "examples": {"B": "どう展開するかわかってる。バカなキャラを演じ続けて、型にはまり続けるんだ。", "C": "自分のビジネス始めたの？おめでとう！どう展開するか楽しみ。", "D": "展開する。"}},
159: {"nativeDefinition": "Used to introduce a slightly unrelated comment.", "japaneseMeaning": "話は変わるけど、脱線するけど", "etymology": "off-topic（話題から外れて）で、本題から少し外れる前置き。", "examples": {"B": "ちょっと脱線するけど、スタバの抹茶ラテ大好き。", "C": "「ドーナツって最高だよね」って言われて「わかる」って返した。あ、脱線するけど、ドーナツの綴りが2通りあることに気づいた。", "D": "話題には関係ないが…"}},
160: {"nativeDefinition": "To watch or consume something for an extended period without stopping.", "japaneseMeaning": "（〜を）一気見する、はまる", "etymology": "binge（飲み食いし放題）が視聴や消費にも使われる。", "examples": {"B": "いつものNetflix一気見の代わりに、今週末はハイキングに行くつもり。", "C": "新シリーズ手に入れたから今夜全部一気見する。", "D": "何かを長時間ノンストップで見る。"}},
161: {"nativeDefinition": "To tease or joke with someone.", "japaneseMeaning": "（人を）からかう、冗談を言う", "etymology": "pull one's leg（足を引っ張る）で、からかうことを表す。", "examples": {"B": "友達の前でからかったから今怒られてる。仲直りして関係を修復する。", "C": "からかってるの？この公園に蛇がいるなんて都市伝説でしょ。", "D": "（人を）からかう。"}},
162: {"nativeDefinition": "Out of public view; happening secretly.", "japaneseMeaning": "舞台裏で、水面下で", "etymology": "behind the scenes（舞台の裏）で、表に出ない活動を表す。", "examples": {"B": "舞台裏ではたくさんのチェック体制があって、スタッフの横領を防いでる。", "C": "物事を動かし続けるために舞台裏で働いてる人がたくさんいることを忘れちゃダメ。", "D": "公の目から離れて。"}},
163: {"nativeDefinition": "To live primarily for something or someone one loves.", "japaneseMeaning": "（〜のために）生きている、〜が生きがい", "etymology": "live for（〜のために生きる）で、何かが人生の中心であることを表す。", "examples": {"B": "ジョニーは本当に仕事のために生きてるの？信じられない。", "C": "旅行が生きがいだから、ナンシーが喫煙者なのは僕にとって致命的。", "D": "何かや誰かを愛する。"}},
164: {"nativeDefinition": "Honestly; speaking frankly.", "japaneseMeaning": "正直に言うと、本音を言えば", "etymology": "real talk（本当の話）で、率直な意見を述べる前置き。", "examples": {"B": "正直に言うと、前の動画はちょっと微妙だったけど、今回のは間違いなく最高。", "C": "正直に言うと、在宅勤務は最高。みんなやるべきだ。", "D": "正直に。"}},
165: {"nativeDefinition": "If you don't use a skill, you will lose it.", "japaneseMeaning": "使わなければ衰える、継続が大事", "etymology": "use it or lose it（使うか失うか）のことわざ。", "examples": {"B": "外国語の学習は筋肉と同じ。使わなければ衰える。", "C": "ゴルフスイングは以前すごく良かったけど、数ヶ月打ってなくてちょっと鈍った。使わなければ衰えるね。", "D": "練習しなければ失う。"}},
166: {"nativeDefinition": "Someone worth keeping in a relationship.", "japaneseMeaning": "手放しちゃダメな人、逸材", "etymology": "keeper（保管する価値がある人）のスラング。", "examples": {"B": "彼氏、家事全部やって給料も君と同じくらい稼いでる。絶対手放しちゃダメな人だよ。", "C": "彼女すごく綺麗だね。ラッキーだよ。絶対手放しちゃダメ。", "D": "手元に置く価値がある人。"}},
167: {"nativeDefinition": "To remind someone of a past time or place.", "japaneseMeaning": "（〜を）思い出させる", "etymology": "take back（過去に連れ戻す）で、懐かしさを呼び起こすことを表す。", "examples": {"B": "ジュリアンと話して、経理部で働いてた頃を思い出した。", "C": "この匂い、祖父母の家を思い出す。", "D": "（人に）何かを思い出させる。"}},
168: {"nativeDefinition": "What is someone's opinion on something?", "japaneseMeaning": "（〜について）どう思う？", "etymology": "thoughts on（〜についての考え）で、意見を尋ねる表現。", "examples": {"B": "ピンクの車を買うの、どう思う？", "C": "今夜の飲み会を中止するの、どう思う？他のみんなもあまり乗り気じゃなさそう。", "D": "（人は）何かについてどう考える？"}},
169: {"nativeDefinition": "To miss an opportunity.", "japaneseMeaning": "（チャンスを）逃す、乗り遅れる", "etymology": "miss the boat（船を逃す）で、機会を逃すことを表す。", "examples": {"B": "先週見てた株が数日で10ドルから100ドルになった。完全に乗り遅れた。", "C": "Switch買いたいんだけど、どこも売り切れ。今回はチャンス逃した。", "D": "チャンスを逃す。"}},
170: {"nativeDefinition": "The main earner in a household.", "japaneseMeaning": "稼ぎ手、家計を支える人", "etymology": "bread（パン）＋ winner（稼ぐ人）で、家族の生活を支える人を表す。", "examples": {"B": "昔は普通、稼ぎ手は男性だったけど、今では古臭く聞こえるね。", "C": "はっきり言うけど、うちの稼ぎ手になる気はない。のんびりゲームしてたい。", "D": "主たる収入者。"}},
171: {"nativeDefinition": "To make a short speech.", "japaneseMeaning": "（短い）挨拶をする、一言述べる", "etymology": "a few words（いくつかの言葉）で、短いスピーチを表す。", "examples": {"B": "食事の前に、今日みんながここに集まった理由について一言述べさせて。", "C": "この素晴らしいイベントで一言述べさせてくれてありがとう。あなたとチームに乾杯。", "D": "短いスピーチをする。"}},
172: {"nativeDefinition": "To listen to someone attentively and sympathetically.", "japaneseMeaning": "（人の話を）聞く、耳を貸す", "etymology": "lend one's ear（耳を貸す）で、話を聞いてもらうことを表す。", "examples": {"B": "少し耳を貸してくれる？吐き出したいことがあって、君だけが信頼できる。", "C": "5分後に今の仕事を止めて耳を貸すから。", "D": "（人の話を）聞く。"}},
173: {"nativeDefinition": "Providing good value relative to cost.", "japaneseMeaning": "費用対効果が高い、コスパがいい", "etymology": "cost（費用）＋ effective（効果的）の複合語。", "examples": {"B": "AIを素早く習得するには、これらのウェビナーが最もコスパがいい方法の一つだよ。", "C": "後から思えば、大学時代にもっと勉強すべきだった。毎晩クラブに行くよりコスパがいい。", "D": "費用対効果が高い。"}},
174: {"nativeDefinition": "To join a popular trend or activity.", "japaneseMeaning": "（流行に）乗る、バンドワゴンに飛び乗る", "etymology": "bandwagon（勝者の楽団車）に jump on（飛び乗る）で、流行に乗ることを表す。", "examples": {"B": "Zoomの流行に乗った。正直、Skypeと何が違うのかわからない。", "C": "ポッドキャストの流行に乗ったんだ。英雄見心あい。退屈な作業中に聴いてる。", "D": "人気になった活動に参加する。"}},
175: {"nativeDefinition": "The more you practice, the better you become.", "japaneseMeaning": "習うより慣れろ、練習が完璧を作る", "etymology": "practice（練習）＋ makes perfect（完璧を作る）のことわざ。", "examples": {"B": "トップレベルで成功したいなら手を抜いちゃダメ。練習が完璧を作る。それが真実。", "C": "人前で話すのは嫌いだけど、できるだけやってる。練習が完璧を作るから。", "D": "練習すればするほど上手になる。"}},
176: {"nativeDefinition": "To discuss something with someone before deciding.", "japaneseMeaning": "（〜を）相談する、確認する", "etymology": "run by（そばを走る）で、誰かに確認することを表す。", "examples": {"B": "今週末ゴルフに参加したいけど、まず奥さんに相談しないと。", "C": "いいアイデアに聞こえるけど、方向が違うと思う。ジョージに相談した方がいい。", "D": "（人に）何かを相談する。"}},
177: {"nativeDefinition": "Used when discovering an unexpected connection between people.", "japaneseMeaning": "世間は狭いね", "etymology": "small world（小さな世界）で、思いがけない繋がりを表す。", "examples": {"B": "アテネのバスで君のいとこに偶然会うなんて。世間狭いね。", "C": "君もアラスカ出身？わあ、世間狭い！", "D": "遠く離れた場所の人々もつながっている。"}},
178: {"nativeDefinition": "To claim credit for something one did not do.", "japaneseMeaning": "（〜の）手柄を横取りする", "etymology": "take credit（評価を取る）で、自分の手柄にすることを表す。", "examples": {"B": "会社は軌道に乗った。新CEOはほとんど何もしてないのに、全部の手柄を横取りした。", "C": "何でも手柄を横取りしようとする人は本当にイライラする。", "D": "（〜の）賞賛を主張する。"}},
179: {"nativeDefinition": "To make a change for variety.", "japaneseMeaning": "（気分転換に）変える、切り替える", "etymology": "switch it up（切り替える）で、変化をつけることを表す。", "examples": {"B": "気分転換にロンドンで働くつもり。すごくワクワクしてる。", "C": "切り替えて今日は外でランチしよう。", "D": "変化をつける。"}},
180: {"nativeDefinition": "A situation where one feels safe and at ease.", "japaneseMeaning": "コンフォートゾーン、安心できる領域", "etymology": "comfort（快適）＋ zone（領域）で、安心できる範囲を表す。", "examples": {"B": "仕事では今コンフォートゾーンにいるけど、学習と成長の面で行き詰まってる。", "C": "視野を広げたいならコンフォートゾーンから出なきゃ。", "D": "安心できる状況や場所。"}},
181: {"nativeDefinition": "To pause and consider from a broader perspective.", "japaneseMeaning": "一歩引いて、距離を置いて考える", "etymology": "step back（後ろに下がる）で、視点を離れることを表す。", "examples": {"B": "時には一歩引いて、違うレンズで物事を見るのはいいことだ。", "C": "一歩引いて、このプロジェクトの全体像を見よう。", "D": "一時停止する。"}},
182: {"nativeDefinition": "To let someone enter a building by buzzing them in.", "japaneseMeaning": "（インターホンで）入れてあげる", "etymology": "buzz（ブザーを鳴らす）＋ in（中へ）で、インターホンで入れることを表す。", "examples": {"B": "着いたら連絡して。入れてあげるから。", "C": "大家さんはUber Eatsの配達員を入れるのを嫌がるから、ロビーで受け取らなきゃ。", "D": "（人を）入れる。"}},
183: {"nativeDefinition": "To cost a lot of money.", "japaneseMeaning": "大金がかかる、財布を痛める", "etymology": "break the bank（銀行を破綻させる）で、非常に高価なことを表す。", "examples": {"B": "白いTシャツ1枚800ドル？財布が痛むよ。", "C": "素晴らしい時計が必ずしも大金をかける必要はない。500ドルでいいのはたくさんある。", "D": "高すぎる。"}},
184: {"nativeDefinition": "Full of software bugs or glitches.", "japaneseMeaning": "（ソフトが）バグだらけの、不具合がある", "etymology": "bug（虫＝不具合）＋ -y で、バグが多いことを表す。", "examples": {"B": "あの新OSはちょっとバグだらけだから、まだインストールしない方がいい。", "C": "君のスマホでもアプリがバグだらけ？それとも俺だけ？", "D": "動作が遅い。"}},
185: {"nativeDefinition": "In other words; to express something differently.", "japaneseMeaning": "別の言い方をすると、言い換えれば", "etymology": "put it another way（別の方法で言う）で、言い換えを表す。", "examples": {"B": "今週金曜誰がオフィスに来る？言い換えれば、仕事終わりに飲みに行きたい人は？", "C": "自信は経験からしか生まれない。言い換えれば、行動しなければ自信は一生つかない。", "D": "言い換えれば。"}},
186: {"nativeDefinition": "To walk to relieve discomfort or stress.", "japaneseMeaning": "（散歩して）気を紛らわす、歩いて消化する", "etymology": "walk it off（歩いて取る）で、散歩して気分を転換することを表す。", "examples": {"B": "保存し忘れてエッセイを最初から書き直し？散歩して気を紛らわせな。今度は早く終わるよ。", "C": "食べ過ぎた。散歩して消化する。30分後に戻る。", "D": "耐える。気分を良くするために歩く。"}},
187: {"nativeDefinition": "There is a limit to what someone can do.", "japaneseMeaning": "（人に）できることには限界がある", "etymology": "only so much（それだけ）で、限られた範囲しかできないことを表す。", "examples": {"B": "投資家はいつもマイナスに触れると思うかもしれないけど、この経済危機ではできることには限界がある。", "C": "新しい彼氏を探すのは頑張るけど、できることには限界がある。", "D": "（人が）取れる行動には限界がある。"}},
188: {"nativeDefinition": "To suddenly stop all communication with someone.", "japaneseMeaning": "（人を）ゴーストする、連絡を突然絶つ", "etymology": "ghost（幽霊）が消えるように、突然連絡を絶つスラング。", "examples": {"B": "なんでゴーストされたのか考えてる。可愛いお腹のせいかも。", "C": "途中でゴーストされた。ほんとがっかり。", "D": "（人への）連絡を止める。"}},
189: {"nativeDefinition": "One's personal opinion, often modestly offered.", "japaneseMeaning": "個人的な意見、一存の見解", "etymology": "two cents（2セント）で、価値のない意見という謙遜表現。", "examples": {"B": "個人的な意見だけど、この家を買うなら今日決断しないと。", "C": "個人的な意見だけど、もっと会議で発言した方がいいと思う。", "D": "（人の）意見。"}},
190: {"nativeDefinition": "Potential for improvement.", "japaneseMeaning": "改善の余地、伸びしろ", "etymology": "room（余地）＋ improvement（改善）で、向上の可能性を表す。", "examples": {"B": "完璧なタブレットだと言ってるけど、改善の余地はすごくあると思う。", "C": "守備スキルにはまだ改善の余地がたくさんあるから、もっと練習に励む。", "D": "向上の範囲。"}},
191: {"nativeDefinition": "Unable to forget something one has seen.", "japaneseMeaning": "（見たものを）忘れられない", "etymology": "unsee（見なかったことにする）の否定で、見たものが頭から消えないことを表す。", "examples": {"B": "送ってくれた動画はヤバいと思った。当たりで、もう忘れられない。", "C": "コンセントが豚の鼻に見えるって言われて、もう忘れられない。", "D": "何かの光景を忘れられない。"}},
192: {"nativeDefinition": "To feel uncomfortable or wrong about something.", "japaneseMeaning": "（〜が）しっくりこない、納得できない", "etymology": "sit right（正しく座る）の否定で、違和感があることを表す。", "examples": {"B": "スマブラでマリオが26歳ってこと、しっくりこない。", "C": "永遠に生きられないって事実、納得できない。不死になりたい。", "D": "（人が）受け入れにくい。"}},
193: {"nativeDefinition": "There is strong pressure to succeed or perform.", "japaneseMeaning": "プレッシャーがかかっている", "etymology": "pressure（圧力）が on（かかっている）で、重圧があることを表す。", "examples": {"B": "新製品を予定通り発売するには来週から全力でいかないと。プレッシャーがかかってる。", "C": "試験に合格したいなら明日までにこの章を完璧にしないと。プレッシャーだ。", "D": "賭けが高い。"}},
194: {"nativeDefinition": "To take a less active or prominent role.", "japaneseMeaning": "（主導権を）譲る、脇に回る", "etymology": "back seat（後部座席）で、主役から外れることを表す。", "examples": {"B": "普段はコントロール好きだけど、今回は脇に回ることにした。", "C": "上司がいるときは脇に回った方がいい。今日機嫌悪いから。", "D": "重要度の低い立場に回る。"}},
195: {"nativeDefinition": "Directly; from personal experience.", "japaneseMeaning": "直接、自分の経験で", "etymology": "firsthand（第一の手）で、直接体験することを表す。", "examples": {"B": "家を買いたいのはわかるけど、先走りちゃダメ。決める前に直接見るべき。", "C": "自分の経験で、自分のことしか考えない役員がたくさんいるのは知ってる。考えるだけで腹が立つ。", "D": "個人的に。"}},
196: {"nativeDefinition": "To learn something through a difficult or painful experience.", "japaneseMeaning": "（苦い経験で）身をもって学ぶ", "etymology": "the hard way（難しい方法）で、失敗を通じて学ぶことを表す。", "examples": {"B": "インフルエンザは軽く見ちゃダメ。先月身をもって学んだ。", "C": "ドットコムバブルが崩壊したとき、良いことにも終わりがあると身をもって学んだ。", "D": "ネガティブな経験を通じて学ぶ。"}},
197: {"nativeDefinition": "To mind one's own business; not interfere.", "japaneseMeaning": "自分の役割に徹する、余計な口出しをしない", "etymology": "stay in one's lane（自分の車線に留まる）で、自分の分野に専念することを表す。", "examples": {"B": "この環境でクビにならない最善の方法は、自分の役割に徹してうまく立ち回ること。", "C": "私の自由時間はあなたの知ることじゃない。余計な口出ししないで。", "D": "自分の仕事に専念する。"}},
198: {"nativeDefinition": "Unable to identify exactly what is wrong or different.", "japaneseMeaning": "（理由が）はっきり言えない、ピンとこない", "etymology": "put one's finger on（指を置く）の否定で、正確に特定できないことを表す。", "examples": {"B": "この絵、何かおかしいんだけど、はっきり言えない。", "C": "今日なんか違うね。理由ははっきり言えないけど。", "D": "何かの正確な理由を突き止められない。"}},
199: {"nativeDefinition": "The same here; me too.", "japaneseMeaning": "同感、私も", "etymology": "ditto（同上）の口語的な同意表現。", "examples": {"B": "彼の言うことに困ってる？私も。", "C": "金持ちが見下して話すのが嫌？同感。", "D": "同意。"}},
200: {"nativeDefinition": "To be stuck in a boring, unchanging routine.", "japaneseMeaning": "（マンネリに）はまっている、行き詰まっている", "etymology": "rut（轍）に stuck（はまる）で、同じ道を繰り返すことを表す。", "examples": {"B": "仕事がちょっとマンネリにはまってる気がする。そろそろキャリアチェンジが必要。", "C": "深いマンネリにはまってる。Amazon Primeで同じものを何度も見てる。", "D": "変わらない状況にいる。"}},
}
